patch:
--- a/comparator.vhd
+++ b/comparator.vhd
@@ -1,18 +1,18 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity comparator_64bit is
   port(
     a : in std_logic_vector(63 downto 0);
     b : in std_logic_vector(63 downto 0);
     equal : out std_logic
   );
 end entity;

 architecture rtl of comparator_64bit is
 begin
-  process(a)
+  process(a, b)
   begin
     if (a = b) then
       equal <= '1';
     else
       equal <= '0';
     end if;
   end process;

